scwin.onpageload = async function() {

	scwin.lobranCd    = $c.gus.cfIsNull($c.data.getMemInfo("lobranCd")) ? "" : $c.data.getMemInfo("lobranCd");
	scwin.vCurDate    = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
    scwin.subVcurDate = scwin.vCurDate.substring(0, 6);
	scwin.vwrkStDt    = scwin.subVcurDate + "01";                                       // 입항예정일자 from(현재 날짜가 포함된 달의 시작 일자)
	scwin.vwrkEndDt   = scwin.subVcurDate + $c.date.getLastDateOfMonth(scwin.subVcurDate);    // 입항예정일자 to(현재 날짜가 포함된 달의 마지막 일자)

    scwin.del_staffNo       = "";
    scwin.del_valueCheck    = 0;
    scwin.del_occpgrdNm     = "";
    scwin.del_occpgrdCd     = 0;
    scwin.del_chief         = 0;
    scwin.v_workClsCd       = ""; 
    scwin.bOnPopUp          = false;

    const codeOptions = [
        { grpCd : "OP316", compID : "acb_wrkPlClsCd" },

    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);


};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        scwin.f_initSetTab(); //tab세팅	

    }, {"delay":50});
};

scwin.setCommonCodeCallBack = async function(){

    ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
    ds_combo1_search.set("queryId", "retriveLobranCodeList");
    var rs = await $c.sbm.execute(sbm_combo1);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        ds_combo1.setJSON(rs.responseJSON.GAUCE);
        ds_combo1.sort("code", 0);

    };

    acb_wrkPlClsCd.addItem("전체", "", "", 0);
    acb_wrkPlClsCd.setSelectedIndex(0);

    scwin.f_SetDefaultData();

    // acb_lobranCd.setValue("4AA");
    // // ica_wrkDt.setValue("202404");
    // ica_wrkDt.setValue("202112");
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {
	ica_wrkDt.setValue(scwin.vCurDate);  
	acb_lobranCd.setValue(scwin.lobranCd);
	acb_lobranCd.focus();
};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {  
    // $c.gus.cfEnableObjects([tab_1, tab_2, tab_3]);
    tac_tabControl1.setSelectedTabIndex(0);
};

//-------------------------------------------------------------------------
// 본선작업계획현황조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	// 검색조건 필수 입력 체크
  	if (!await $c.gus.cfValidate([acb_lobranCd, ica_wrkDt])) {
  		return;
	}
	$c.sbm.execute(sbm_retrieve);
};

scwin.f_gridToExcel = function (argGrid, argTitle) {
    // Title
    // argGrid.SetExcelTitle(0, "");
    // argGrid.SetExcelTitle(1,"value:" + argTitle + ";" // 표시할 타이틀
    //                       + "font-face:'돋움체';"      // 폰트
    //                       + "font-size:16pt;"         // 폰트 크기
    //                       + "font-color:black;"       // 폰트 색깔
    //                       + "bgcolor:#ffffff;"        // 배경 색깔
    //                       + "align:center;"           // 정렬
    //                       + "line-color:white;"       // 타이틀 부분 테두리선 색깔
    //                       + "line-width:0pt;"         // 타이틀 테두리선 굵기
    //                       + "skiprow:1;");            // 타이틀 다음 떼는 로우 수
    // // 검색조건
    // var vDay = "점소 : " + acb_lobranCd.ValueOfIndex("lobranNm",acb_lobranCd.Index) + " : "
    //          + "작업일자 : " + ica_wrkDt.text;
    // var vSearchOption = ";font-face:굴림체;font-size:10pt;font-color:black;bgcolor:#ffffff;align: left;line-color:red;line-width:0pt;";
    // argGrid.SetExcelTitle(1, "value:" + vDay.replace(/:/g,'|').replace(/;/g,'') + vSearchOption );
    // cfGridToExcel(argGrid, argTitle, argTitle+".xls", 4+8+16);
    // var selectedIdx = acb_lobranCd.getSelectedIndex();
    // var selectedItem = acb_lobranCd.getItem(selectedIdx);
    var colCount = 0;
    for (var i = 0 ; i < argGrid.getTotalCol() ; i ++){
        if (argGrid.getColumnVisible(i)){
            colCount++;
        }
    }
    var vDay = "점소 | " + acb_lobranCd.getText(true) + " | "
             + "작업일자 | " + ica_wrkDt.getValue();
    const infoArr = [
        {
          rowIndex    : 0
        , colIndex    : 0
        , rowSpan     : 1
        , colSpan     : colCount
        , text        : argTitle
        , textAlign   : "center"
        , fontSize    : 24
        , fontName    : "돋움체"
        , color       : "black"
        , fontWeight  : ""
        , drawBorder  : "false"
        , borderColor : ""
        , borderWidth : ""
        , wordWrap    : "true"
        , bgColor     : "#ffffff"
    },
    {
          rowIndex    : 2
        , colIndex    : 0
        , rowSpan     : 1
        , colSpan     : colCount
        , text        : vDay
        , textAlign   : "left"
        // , fontSize    : "12pt"
        , fontName    : "돋움체"
        , color       : "black"
        , fontWeight  : ""
        , drawBorder  : "false"
        , borderColor : ""
        , borderWidth : ""
        , wordWrap    : "true"
        , bgColor     : "#ffffff"
    }

    ];
    const options = {
        fileName : argTitle + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: argTitle,
        type : "1",
        startRowIndex: 3,
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(argGrid, options, infoArr);
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  	// 선언부
	var rtnList;  // 공통POP-UP -> 요청화면 	

	switch (disGubun) {
  		case 1:
			var arrParam = new Array();
 			arrParam[0] = pCode; //사번
            arrParam[1] = pName; //사원명
            arrParam[2] = acb_lobranCd.BindColVal; //점소코드
            arrParam[3] = acb_lobranCd.text;  //점소명
            arrParam[4] = ''; //작업장코드
            arrParam[5] = '';//직종  (정규직)
            arrParam[6] = lc_dtlOccptypeCd.BindColVal; //상세직종코드 
            arrParam[7] = ''; //직급
            arrParam[8] = '';  //작업일
            arrParam[9] = ''; //배치가능여부
 			arrParam[10] = 'T'; //WINDOW CLOSE 여부
 			arrParam[11] = "1"; //상세직종Flag

 			// rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	

            let win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";
            let opts = {
                id : "Pop"
                , popupName : ""
                , modal : true
                , type : "browserPopup"
                , width : 840
                , height : 400
                , title : ""
            };
            var rtnList = await $c.win.openPopup(win_url, opts, arrParam);


 		   //(0)직종코드		
           //(1)직종명	        
           //(2)인원번호		
           //(3)인원명	                          
           //(4)직급		    
           //(5)직급명		    
           //(6)물류점소코드   
           //(7)물류점소명		
           //(8)상세직종코드	
           //(9)상세직종명		                  
           //(10)배치가능여부	
           //(11)본사계약직여부 
           //(12)연근여부		

			if (rtnList != null ) {
			    ed_staffNo.setValue(rtnList[2]);	//사원코드
			    txt_staffNm.setValue(rtnList[3]);	//사원명
		 	}else{
		 	    ed_staffNo.setValue('');	//사원코드
			    txt_staffNm.setValue('');	//사원명
		 	}
		break;			
	}
};

//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
//-------------------------------------------------------------------------
scwin.f_InitObjects = function () {
	$c.gus.cfInitObjects(tb_mainData);
	scwin.f_SetDefaultData();
};

scwin.f_openDetailPopup = async function (){
 	var args = new Array();
	args[0] = scwin.del_staffNo;
	args[1] = scwin.del_valueCheck; 
	args[2] = ica_wrkDt.getValue();
	args[3] = scwin.del_occpgrdCd;
	args[4] = scwin.del_chief;
	// window.showModalDialog('/ds/op/stvwrk/op_210_02_13p.jsp?paramTitle=상용직근무실적상세팝업',args,"dialogWidth:600px; dialogHeight:370px; status:No");	
    let win_url = "/ui/ds/op/stvwrk/op_210_02_13p.xml";
    let opts = {
        id : "detailPop"
        , popupName : "상용직근무실적상세팝업"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 600
        , title : "상용직근무실적상세팝업"
    };
    var rtnList = await $c.win.openPopup(win_url, opts, args);
};

scwin.f_ClickEvent = function (row, colid){
	var cnt_Weather     = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "weatherCnt");
	var cnt_Single      = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "singleCnt");
	var cnt_Emer        = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "emerCnt");
	var cnt_Move        = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "moveCnt");
	scwin.del_staffNo   = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "staffNo");

    if (cnt_Weather == 0 && cnt_Single == 0 && cnt_Emer == 0 && cnt_Move == 0) return;
	if (ds_extdWrk.getCellData(row, "groupLv1") == "간부"){
		scwin.del_chief = 1;
	}else{
		scwin.del_chief = 0;
	}

	if (ds_extdWrk.getCellData(row, "occpgrdCd") == "" && scwin.del_chief == 0){
		scwin.del_occpgrdCd = ds_extdWrk.getCellData(row - 1, "occpgrdCd"); //구분값이 간부인 값을 제외한 SUM행일 경우, 마지맥 행의 구분코드 가져와서 대입.
	}else{
		scwin.del_occpgrdCd = ds_extdWrk.getCellData(row, "occpgrdCd");
	}

	if (cnt_Weather != "" && colid == "weatherCnt"){
		scwin.del_valueCheck = 1;
		scwin.f_openDetailPopup();
	}
	else if (cnt_Single != "" && colid == "singleCnt"){
		scwin.del_valueCheck = 2;
		scwin.f_openDetailPopup();
	}
	else if (cnt_Emer != "" && colid == "emerCnt"){
		scwin.del_valueCheck = 3;
		scwin.f_openDetailPopup();
	}
	else if (cnt_Move != "" && colid == "moveCnt"){
		scwin.del_valueCheck = 4;
		scwin.f_openDetailPopup();
	}
};

scwin.gr_extdWrk_onsubtotaldblclick = function (info) {
    if (info.colID == "weatherCnt_s1" || info.colID == "singleCnt_s1"
     || info.colID == "emerCnt_s1" || info.colID == "moveCnt_s1") {
        var startRowIdx = info.startRowIndex;
        var endRowIdx = info.endRowIndex;
        var cnt_Weather = 0;
        var cnt_Single = 0;
        var cnt_Emer = 0;
        var cnt_Move = 0;

        for (var i = startRowIdx ; i <= endRowIdx ; i++) {
            cnt_Weather += $c.gus.cfIsNull(ds_extdWrk.getCellData(i, "weatherCnt")) ? 0 : ds_extdWrk.getCellData(i, "weatherCnt")*1;
            cnt_Single += $c.gus.cfIsNull(ds_extdWrk.getCellData(i, "singleCnt")) ? 0 : ds_extdWrk.getCellData(i, "singleCnt")*1;
            cnt_Emer += $c.gus.cfIsNull(ds_extdWrk.getCellData(i, "emerCnt")) ? 0 : ds_extdWrk.getCellData(i, "emerCnt")*1;
            cnt_Move += $c.gus.cfIsNull(ds_extdWrk.getCellData(i, "moveCnt")) ? 0 : ds_extdWrk.getCellData(i, "moveCnt")*1;
        }

        scwin.del_staffNo = "";

        if (cnt_Weather == 0 && cnt_Single == 0 && cnt_Emer == 0 && cnt_Move == 0) return;
        if (ds_extdWrk.getCellData(info.startRowIndex, "groupLv1") == "간부"){
            scwin.del_chief = 1;
        }else{
            scwin.del_chief = 0;
        }

        if (ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd") == "" && scwin.del_chief == 0){
            scwin.del_occpgrdCd = ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd"); //구분값이 간부인 값을 제외한 SUM행일 경우, 마지맥 행의 구분코드 가져와서 대입.
        }else{
            scwin.del_occpgrdCd = ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd");
        }

        if (cnt_Weather != "" && info.colID == "weatherCnt_s1"){
            scwin.del_valueCheck = 1;
            scwin.f_openDetailPopup();
        }
        else if (cnt_Single != "" && info.colID == "singleCnt_s1"){
            scwin.del_valueCheck = 2;
            scwin.f_openDetailPopup();
        }
        else if (cnt_Emer != "" && info.colID == "emerCnt_s1"){
            scwin.del_valueCheck = 3;
            scwin.f_openDetailPopup();
        }
        else if (cnt_Move != "" && info.colID == "moveCnt_s1"){
            scwin.del_valueCheck = 4;
            scwin.f_openDetailPopup();
        }

    };
};



scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_InitObjects();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.excelDown1 = function(){
    scwin.f_gridToExcel(gr_wrkRslts,'노무원실적');
};

scwin.excelDown2 = function(){
    scwin.f_gridToExcel(gr_extdWrk,'연장시간급여');
};

scwin.excelDown3 = function(){
    scwin.f_gridToExcel(gr_extdWrk_detail,'연장시간급여');
};

scwin.f_decodeVal = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = Math.floor(floatVal);
        return $c.gus.cfInsertComma(formattedVal);
    }
}

scwin.f_decodeVal_1 = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = Math.floor(floatVal * 10)/10;

        formattedVal = $c.gus.cfInsertComma(formattedVal) 
        var formattedArr = formattedVal.split(".");

        if (!(formattedArr.length > 1)){
            formattedVal = formattedVal + ".0";
        }

        return formattedVal;
    }
}

scwin.f_decodeVal_2 = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = Math.floor(floatVal * 100)/100; 
        formattedVal = $c.gus.cfInsertComma(formattedVal) 
        var formattedArr = formattedVal.split(".");

        if (!(formattedArr.length > 1)){
            formattedVal = formattedVal + ".00";
        }

        return formattedVal;
    }
}

scwin.sbm_retrieve_submit = function (e) {
    ds_condition.set("lobranCd", acb_lobranCd.getValue());
    ds_condition.set("wrkDt", ica_wrkDt.getValue());
    ds_condition.set("wrkPlClsCd", acb_wrkPlClsCd.getValue());

};

scwin.sbm_retrieve_submitdone = function (e) {
	// 총 조회건수 표시
    var wrkRsltsRowCnt = ds_wrkRslts.getRowCount()
    txt_totalRows.setValue(wrkRsltsRowCnt);

	// 총 조회건수 표시
    var extdWrkRowCnt = ds_extdWrk.getRowCount()
    txt_totalRows2.setValue(extdWrkRowCnt);
    txt_totalRows3.setValue(extdWrkRowCnt);

    gr_extdWrk.setColumnStyle("weatherCnt", "cursor", "pointer");
    gr_extdWrk.setColumnStyle("singleCnt", "cursor", "pointer");
    gr_extdWrk.setColumnStyle("emerCnt", "cursor", "pointer");
    gr_extdWrk.setColumnStyle("moveCnt", "cursor", "pointer");


};

scwin.sbm_retrieve_submiterror = function (e) {

};

scwin.gr_extdWrk_detail_oncelldblclick = function (rowIndex, columnIndex, columnId) {

};

scwin.tac_tabControl1_ontabload = function (tabId, index, userId) {
};

scwin.gr_extdWrk_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    var ch = ds_extdWrk.getCellData(rowIndex, "groupLv1");
	if ((ch.trim() != "계" && ch.trim() != "합계")){
		scwin.f_ClickEvent(rowIndex, columnId);
	}
};
